"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "@/context/AuthContext";
import {
  DollarSign,
  Plus,
  Loader2,
  ArrowLeft,
  Trash2,
  Edit,
  DollarSign as PriceIcon,
  ShieldCheck,
  ShieldX,
  AlertCircle,
} from "lucide-react";

interface TreatmentCost {
  id: string;
  treatmentName: string;
  department: string;
  minCost: number;
  maxCost: number;
  insuranceCovered: boolean;
  description: string | null;
}

export default function HospitalCostsCRUDPage() {
  const router = useRouter();
  const { user, isLoading } = useAuth();
  
  const [costs, setCosts] = useState<TreatmentCost[]>([]);
  const [loading, setLoading] = useState(true);
  const [modalOpen, setModalOpen] = useState(false);
  const [editingCost, setEditingCost] = useState<TreatmentCost | null>(null);

  // Form states
  const [treatmentName, setTreatmentName] = useState("");
  const [department, setDepartment] = useState("");
  const [minCost, setMinCost] = useState("");
  const [maxCost, setMaxCost] = useState("");
  const [insuranceCovered, setInsuranceCovered] = useState(true);
  const [description, setDescription] = useState("");

  const [formSaving, setFormSaving] = useState(false);
  const [formError, setFormError] = useState("");

  const fetchCosts = async () => {
    try {
      setLoading(true);
      const res = await fetch("/api/hospitals/costs");
      const data = await res.json();
      if (data.success) {
        setCosts(data.data.costs);
      }
    } catch (err) {
      console.error("Error fetching treatment costs:", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (!isLoading) {
      if (!user || user.role !== "HOSPITAL") {
        router.push("/login");
        return;
      }
      fetchCosts();
    }
  }, [user, isLoading, router]);

  const openAddModal = () => {
    setEditingCost(null);
    setTreatmentName("");
    setDepartment("");
    setMinCost("");
    setMaxCost("");
    setInsuranceCovered(true);
    setDescription("");
    setFormError("");
    setModalOpen(true);
  };

  const openEditModal = (cost: TreatmentCost) => {
    setEditingCost(cost);
    setTreatmentName(cost.treatmentName);
    setDepartment(cost.department);
    setMinCost(cost.minCost.toString());
    setMaxCost(cost.maxCost.toString());
    setInsuranceCovered(cost.insuranceCovered);
    setDescription(cost.description || "");
    setFormError("");
    setModalOpen(true);
  };

  const handleDelete = async (id: string) => {
    if (!confirm("Are you sure you want to remove this procedure from the catalog?")) return;
    try {
      const res = await fetch(`/api/hospitals/costs?id=${id}`, {
        method: "DELETE",
      });
      const data = await res.json();
      if (data.success) {
        fetchCosts();
      } else {
        alert(data.error || "Failed to delete item.");
      }
    } catch (err) {
      console.error(err);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setFormSaving(true);
    setFormError("");

    // Validate min/max
    if (Number(minCost) > Number(maxCost)) {
      setFormError("Minimum cost cannot exceed maximum cost.");
      setFormSaving(false);
      return;
    }

    const payload = {
      id: editingCost?.id,
      treatmentName,
      department,
      minCost,
      maxCost,
      insuranceCovered,
      description,
    };

    try {
      const res = await fetch("/api/hospitals/costs", {
        method: editingCost ? "PUT" : "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });
      const data = await res.json();
      if (data.success) {
        setModalOpen(false);
        fetchCosts();
      } else {
        setFormError(data.error || "Failed to save treatment info.");
      }
    } catch (err) {
      setFormError("Connection error. Please try again.");
    } finally {
      setFormSaving(false);
    }
  };

  if (isLoading || loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-surface-secondary">
        <div className="flex flex-col items-center gap-4">
          <Loader2 className="w-10 h-10 text-primary-600 animate-spin" />
          <p className="text-text-secondary text-sm">Loading treatment catalog...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-surface-secondary pb-12">
      {/* Header */}
      <header className="bg-white border-b border-border sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <button
              onClick={() => router.push("/dashboard")}
              className="text-text-muted hover:text-text-primary p-2 -ml-2 rounded-lg hover:bg-surface-secondary transition-colors"
            >
              <ArrowLeft className="w-5 h-5" />
            </button>
            <span className="text-lg font-bold text-text-primary">Treatment Cost Catalog</span>
          </div>
          <button
            onClick={openAddModal}
            className="inline-flex items-center gap-1.5 px-4 py-2 bg-primary-600 hover:bg-primary-700 text-white font-semibold text-xs rounded-xl shadow-xs transition-colors cursor-pointer"
          >
            <Plus className="w-4 h-4" /> Add Procedure
          </button>
        </div>
      </header>

      {/* Main Table */}
      <main className="max-w-5xl mx-auto px-4 py-8">
        <div className="mb-6">
          <h1 className="text-2xl font-bold text-text-primary">Medical Procedures Pricing</h1>
          <p className="text-sm text-text-secondary mt-1">Configure pricing schedules and insurance acceptance scopes for your services.</p>
        </div>

        {costs.length === 0 ? (
          <div className="bg-white border border-border rounded-2xl py-16 px-4 text-center">
            <DollarSign className="w-12 h-12 text-text-muted mx-auto mb-4 opacity-50" />
            <h3 className="text-lg font-bold text-text-primary mb-1">Catalog is Empty</h3>
            <p className="text-sm text-text-secondary max-w-sm mx-auto mb-6">
              You haven't listed any treatments yet. List your procedures to let patients find your services and estimate costs.
            </p>
            <button
              onClick={openAddModal}
              className="inline-flex items-center gap-1.5 px-4 py-2 bg-primary-600 hover:bg-primary-700 text-white font-semibold text-xs rounded-xl shadow-xs transition-colors cursor-pointer"
            >
              <Plus className="w-4 h-4" /> Add Treatment Catalog Item
            </button>
          </div>
        ) : (
          <div className="bg-white border border-border rounded-2xl overflow-hidden shadow-xs">
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse">
                <thead>
                  <tr className="bg-surface-secondary/50 border-b border-border">
                    <th className="p-4 text-xs font-bold text-text-primary uppercase tracking-wider">Treatment / Procedure</th>
                    <th className="p-4 text-xs font-bold text-text-primary uppercase tracking-wider">Department</th>
                    <th className="p-4 text-xs font-bold text-text-primary uppercase tracking-wider">Estimated Cost Range</th>
                    <th className="p-4 text-xs font-bold text-text-primary uppercase tracking-wider">Insurance Accepted</th>
                    <th className="p-4 text-xs font-bold text-text-primary uppercase tracking-wider text-right">Actions</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-border text-sm">
                  {costs.map((cost) => (
                    <tr key={cost.id} className="hover:bg-surface-secondary/20">
                      <td className="p-4 font-semibold text-text-primary">
                        <div>{cost.treatmentName}</div>
                        {cost.description && <div className="text-xs text-text-muted mt-0.5 font-normal">{cost.description}</div>}
                      </td>
                      <td className="p-4 text-text-secondary">{cost.department}</td>
                      <td className="p-4 font-bold text-text-primary">₹{cost.minCost.toLocaleString()} - ₹{cost.maxCost.toLocaleString()}</td>
                      <td className="p-4">
                        {cost.insuranceCovered ? (
                          <span className="inline-flex items-center gap-1 text-xs px-2.5 py-0.5 bg-emerald-50 text-emerald-700 border border-emerald-200 rounded-md font-semibold">
                            <ShieldCheck className="w-3.5 h-3.5" /> Yes
                          </span>
                        ) : (
                          <span className="inline-flex items-center gap-1 text-xs px-2.5 py-0.5 bg-surface-secondary text-text-muted border border-border rounded-md font-medium">
                            <ShieldX className="w-3.5 h-3.5" /> No
                          </span>
                        )}
                      </td>
                      <td className="p-4 text-right">
                        <div className="flex items-center justify-end gap-1.5">
                          <button
                            onClick={() => openEditModal(cost)}
                            className="p-1.5 hover:bg-surface-secondary text-primary-600 hover:text-primary-800 rounded-lg transition-colors cursor-pointer"
                          >
                            <Edit className="w-4 h-4" />
                          </button>
                          <button
                            onClick={() => handleDelete(cost.id)}
                            className="p-1.5 hover:bg-red-50 text-error hover:text-red-700 rounded-lg transition-colors cursor-pointer"
                          >
                            <Trash2 className="w-4 h-4" />
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </main>

      {/* Modal */}
      {modalOpen && (
        <div className="fixed inset-0 bg-black/40 backdrop-blur-xs flex items-center justify-center p-4 z-50 animate-fade-in">
          <div className="bg-white border border-border rounded-2xl w-full max-w-md shadow-xl overflow-hidden">
            <div className="p-5 border-b border-border flex justify-between items-center bg-surface-secondary/20">
              <h3 className="font-bold text-text-primary text-base">
                {editingCost ? "Edit Treatment Item" : "Add Procedure Catalog"}
              </h3>
              <button
                onClick={() => setModalOpen(false)}
                className="text-text-muted hover:text-text-primary text-xl font-bold cursor-pointer"
              >
                &times;
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-5 space-y-4">
              {formError && (
                <div className="bg-red-50 border border-red-200 text-red-700 text-xs p-3 rounded-lg flex items-center gap-2 font-semibold">
                  <AlertCircle className="w-4 h-4 flex-shrink-0" />
                  <span>{formError}</span>
                </div>
              )}

              {/* Treatment Name */}
              <div className="space-y-1.5">
                <label className="text-xs font-bold text-text-primary uppercase tracking-wider">Treatment / Procedure Name</label>
                <input
                  type="text"
                  required
                  placeholder="e.g. Angioplasty, MRI Scan"
                  value={treatmentName}
                  onChange={(e) => setTreatmentName(e.target.value)}
                  className="w-full text-sm border border-border rounded-xl px-3.5 py-2 bg-white text-text-primary focus:outline-none focus:border-primary-500"
                />
              </div>

              {/* Department */}
              <div className="space-y-1.5">
                <label className="text-xs font-bold text-text-primary uppercase tracking-wider">Department / Specialty</label>
                <input
                  type="text"
                  required
                  placeholder="e.g. Cardiology, Radiology"
                  value={department}
                  onChange={(e) => setDepartment(e.target.value)}
                  className="w-full text-sm border border-border rounded-xl px-3.5 py-2 bg-white text-text-primary focus:outline-none focus:border-primary-500"
                />
              </div>

              {/* Price Range */}
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-xs font-bold text-text-primary uppercase tracking-wider">Min Cost (₹)</label>
                  <input
                    type="number"
                    required
                    placeholder="e.g. 5000"
                    value={minCost}
                    onChange={(e) => setMinCost(e.target.value)}
                    className="w-full text-sm border border-border rounded-xl px-3.5 py-2 bg-white text-text-primary focus:outline-none focus:border-primary-500"
                  />
                </div>
                <div className="space-y-1.5">
                  <label className="text-xs font-bold text-text-primary uppercase tracking-wider">Max Cost (₹)</label>
                  <input
                    type="number"
                    required
                    placeholder="e.g. 10000"
                    value={maxCost}
                    onChange={(e) => setMaxCost(e.target.value)}
                    className="w-full text-sm border border-border rounded-xl px-3.5 py-2 bg-white text-text-primary focus:outline-none focus:border-primary-500"
                  />
                </div>
              </div>

              {/* Description */}
              <div className="space-y-1.5">
                <label className="text-xs font-bold text-text-primary uppercase tracking-wider">Short Description</label>
                <textarea
                  rows={2}
                  placeholder="Describe treatment scope, average stay duration, etc."
                  value={description}
                  onChange={(e) => setDescription(e.target.value)}
                  className="w-full text-sm border border-border rounded-xl px-3.5 py-2 bg-white text-text-primary focus:outline-none focus:border-primary-500"
                />
              </div>

              {/* Insurance check */}
              <div className="pt-2">
                <label className="flex items-center gap-2.5 text-sm font-semibold text-text-primary cursor-pointer select-none">
                  <input
                    type="checkbox"
                    checked={insuranceCovered}
                    onChange={(e) => setInsuranceCovered(e.target.checked)}
                    className="w-4.5 h-4.5 border-border rounded text-primary-600 focus:ring-primary-500"
                  />
                  <span>Insurance accepts coverage for this procedure</span>
                </label>
              </div>

              <div className="pt-4 border-t border-border flex justify-end gap-3.5">
                <button
                  type="button"
                  onClick={() => setModalOpen(false)}
                  className="px-4 py-2 border border-border text-text-secondary font-semibold text-xs rounded-xl hover:bg-surface-secondary transition-colors cursor-pointer"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  disabled={formSaving}
                  className="px-4 py-2 bg-primary-600 hover:bg-primary-700 text-white font-semibold text-xs rounded-xl shadow-xs transition-colors flex items-center gap-1 cursor-pointer disabled:opacity-50"
                >
                  {formSaving ? (
                    <>
                      <Loader2 className="w-3.5 h-3.5 animate-spin" /> Saving...
                    </>
                  ) : (
                    "Save Procedure"
                  )}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
